import React, { useState, useRef } from "react";

const projects = [
  {
    id: "node-farm",
    emoji: "🌿",
    cat: "Full Stack · Node.js",
    title: "Node Farm",
    period: "Juil. – Août 2024",
    tech: ["HTML", "CSS", "JavaScript", "Node.js", "JSON"],
    desc: "Interface dynamique avec génération de fiches produits à partir de données JSON structurées.",
    blob: "#C8E8F9",
    // 👇 REMPLACE par l'URL de ta vidéo (YouTube embed, ou chemin local /videos/node-farm.mp4)
    video: "https://www.youtube.com/embed/REMPLACE_ICI",
    videoType: "youtube", // "youtube" ou "local"
  },
  {
    id: "backend-auth",
    emoji: "🔐",
    cat: "Backend · Sécurité",
    title: "Backend sécurisé & Auth",
    period: "Juin – Août 2024",
    tech: ["Node.js", "Express.js", "MongoDB", "JWT", "Nodemailer"],
    desc: "Authentification et autorisation via JWT. Gestion des accès aux sections protégées et sécurisation des données dans MongoDB.",
    blob: "#F9C8E8",
    video: "https://www.youtube.com/embed/REMPLACE_ICI",
    videoType: "youtube",
  },
  {
    id: "gestion-commandes",
    emoji: "🛒",
    cat: "Frontend · React",
    title: "Gestion de commandes",
    period: "Fév. – Mars 2024",
    tech: ["React.js", "Redux", "Firebase", "JavaScript"],
    desc: "Interface de gestion de panier avec ajout/modification des articles. Stockage Firebase avec mise à jour en temps réel via Redux.",
    blob: "#D4C8F9",
    video: "https://www.youtube.com/embed/REMPLACE_ICI",
    videoType: "youtube",
  },
  {
    id: "immobilier-api",
    emoji: "🏠",
    cat: "Stage · API REST",
    title: "API Gestion Immobilière",
    period: "Déc. 2024 – Juin 2025",
    tech: ["Node.js", "Express.js", "MongoDB", "JWT", "REST"],
    desc: "API REST sécurisée pour gestion immobilière développée chez Dundill. Conception d'un système sécurisé et évolutif.",
    blob: "#C8F9E8",
    video: "https://www.youtube.com/embed/REMPLACE_ICI",
    videoType: "youtube",
  },
  {
    id: "cloud-virt",
    emoji: "☁️",
    cat: "Cloud · Infrastructure",
    title: "Cloud & Virtualisation",
    period: "Jan. – Fév. 2025",
    tech: ["Cloud Computing", "IaaS", "PaaS", "SaaS", "Virtualisation"],
    desc: "Connaissances en cloud computing (IaaS, PaaS, SaaS). Déploiement simulé de machines virtuelles sur Ubuntu.",
    blob: "#F9F0C8",
    video: "https://www.youtube.com/embed/REMPLACE_ICI",
    videoType: "youtube",
  },
];

export default function Projects() {
  const [activeId, setActiveId] = useState(null);
  const videoRef = useRef(null);

  const handleCardClick = (id) => {
    if (activeId === id) {
      // Deuxième clic → ferme
      setActiveId(null);
      return;
    }
    setActiveId(id);
    // Scroll vers la vidéo après que React re-render
    setTimeout(() => {
      videoRef.current?.scrollIntoView({ behavior: "smooth", block: "center" });
    }, 80);
  };

  const activeProject = projects.find((p) => p.id === activeId);

  return (
    <div className="projects-wrap">
      <div className="section-head reveal-left">
        <h2 className="section-title">Mes Projets ˚✧</h2>
        <div className="section-underline" />
      </div>

      {/* Grille de cartes */}
      <div className="projects-grid stagger-children">
        {projects.map((p) => (
          <div
            key={p.id}
            id={p.id}
            className={`project-card reveal ${activeId === p.id ? "project-card--active" : ""}`}
            onClick={() => handleCardClick(p.id)}
            style={{ cursor: "pointer" }}
          >
            <div className="project-card-blob" style={{ background: p.blob }} />
            <span className="project-emoji">{p.emoji}</span>
            <p className="project-cat">
              {p.cat} · <em style={{ fontStyle: "normal", opacity: 0.7 }}>{p.period}</em>
            </p>

            <h3 className="project-title" style={{ marginBottom: "0.6rem" }}>
              {p.title}
            </h3>

            <p className="project-desc">{p.desc}</p>

            <div className="project-tags">
              {p.tech.map((t) => (
                <span key={t} className="project-tag">{t}</span>
              ))}
            </div>

            <div className="project-foot">
              <span className="project-watch-hint">
                {activeId === p.id ? "▲ Fermer la démo" : "▶ Voir la démo"}
              </span>
            </div>
          </div>
        ))}
      </div>

      {/* Zone vidéo — apparaît sous la grille */}
      {activeProject && (
        <div ref={videoRef} className="video-panel reveal visible">
          <div className="video-panel-header">
            <span className="video-panel-emoji">{activeProject.emoji}</span>
            <div>
              <h3 className="video-panel-title">{activeProject.title}</h3>
              <p className="video-panel-sub">{activeProject.cat}</p>
            </div>
            <button
              className="video-close-btn"
              onClick={() => setActiveId(null)}
              aria-label="Fermer"
            >
              ✕
            </button>
          </div>

          <div className="video-container">
            {activeProject.videoType === "youtube" ? (
              <iframe
                src={activeProject.video}
                title={activeProject.title}
                frameBorder="0"
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                allowFullScreen
              />
            ) : (
              <video controls autoPlay>
                <source src={activeProject.video} type="video/mp4" />
                Votre navigateur ne supporte pas la vidéo.
              </video>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
